// APIError carries HTTP status information for structured exit codes.
type APIError struct {
	Method     string
	Path       string
	StatusCode int
	Body       string
}

func (e *APIError) Error() string {
	return fmt.Sprintf("%s %s returned HTTP %d: %s", e.Method, e.Path, e.StatusCode, e.Body)
}

func newHTTPClient(timeout time.Duration, jar http.CookieJar) *http.Client {
	return &http.Client{Timeout: timeout, Jar: jar}
}

func New(cfg *config.Config, timeout time.Duration, rateLimit float64) *Client {
	homeDir, _ := os.UserHomeDir()
	// PATCH(oauth-login / sync-store-collision): response cache lives under a
	// `responses` subdir so invalidateCache (os.RemoveAll on POST/PUT/DELETE/PATCH)
	// only nukes HTTP response JSON, not store.db (the analytics SQLite that the
	// store package writes to the parent dir). Before this fix, every sync POST
	// silently deleted the store mid-upsert; sync reported success because Close
	// races RemoveAll, but the next command saw zero rows.
	cacheDir := filepath.Join(homeDir, ".cache", "google-search-console-pp-cli", "responses")
	httpClient := newHTTPClient(timeout, nil)
	return &Client{
		BaseURL:    strings.TrimRight(cfg.BaseURL, "/"),
		Config:     cfg,
		HTTPClient: httpClient,
		cacheDir:   cacheDir,
		limiter:    cliutil.NewAdaptiveLimiter(rateLimit),
	}
}

// RateLimit returns the current effective rate limit in req/s. Returns 0 if disabled.
